    TotalErrors       = 0
    CriticalErrors    = 0
    SecurityErrors    = 0
    NetworkErrors     = 0
    FilesystemErrors  = 0
    UIErrors          = 0
    OllamaErrors      = 0
    AuthErrors        = 0
    PerformanceErrors = 0
