            $script:ollamaTimer.Add_Tick({
                    try {
                        Update-OllamaStatusDisplay
                    }
                    catch [System.Management.Automation.PipelineStoppedException] {
                        # Pipeline stopped - silently ignore during shutdown
                    }
                    catch {
